// // This module calculates the two's complement of a 4-bit signed integer. If the input number is positive (most significant bit is 1), the output remains the same as the input. If the input number is negative (most significant bit is 0), the output is calculated by inverting all bits of the input and adding one, effectively converting the negative number to its equivalent positive value.
module top_module(
    input signed [3:0] a,
    output reg signed [3:0] b
);always @(*) begin
    if (a[3] == 0) begin // positive number
        b = a;
    end else begin // negative number
        b = ~a + 1;
    end
end

endmodule
